mapper.delete:
DELETE FROM conquest_map
WHERE member_id      = #{memberId}
  AND trip_place_id  IS NULL
  AND region_id IN (
      SELECT region_id FROM region
      WHERE sido_name        = #{sidoName}
        AND api_sigungu_code IS NULL
  )

mapper.select:
SELECT b.BOOKMARK_ID as bookmarkId, b.PLACE_ID as placeId, p.PLACE_NAME as placeName, p.ADDRESS as address, p.IMAGE_URL as imageUrl, p.CATEGORY as category, b.CREATED_AT as createdAt FROM BOOKMARK b JOIN PLACE p ON b.PLACE_ID = p.PLACE_ID WHERE b.MEMBER_ID = #{memberId}
AND p.CATEGORY = #{type}
ORDER BY b.CREATED_AT DESC
